class Solution:
    def combinationSum(self, c: List[int], t: int) -> List[List[int]]:
        c.sort(); res=[]
        def dfs(i, path, r):
            if r==0: res.append(path[:]); return
            if r<0: return
            for j in range(i, len(c)):
                path.append(c[j]); dfs(j, path, r-c[j]); path.pop()
        dfs(0,[],t); return res

